def correct_bracketing(brackets: str):
    balance = 0
    for c in brackets:
        if c == '(':
            balance += 1
        else:
            balance -= 1
        if balance < 0:
            return False
    return balance == 0

def digitSum(s):
    total = 0
    for char in s:
        if char.isupper():
            total += ord(char)
    return total

def sort_array(array):
    total = sum(array[0] + array[-1])
    if total % 2 == 1:
        return array[:]
    else:
        return sorted(array, reverse=True)

def unique_digits(x):
    result = []
    for num in x:
        if all(int(d) % 2 == 1 for d in str(num)):
            result.append(num)
    return sorted(result)

